import os
from flask import Flask, request, jsonify
from pymongo import MongoClient
from pymongo.errors import ConnectionFailure, OperationFailure
from bson.objectid import ObjectId
from datetime import datetime
import secrets

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', secrets.token_hex(32))

MONGO_USERNAME = os.environ.get('MONGO_USERNAME', 'admin')
MONGO_PASSWORD = os.environ.get('MONGO_PASSWORD', 'password')
MONGO_HOST = os.environ.get('MONGO_HOST', 'localhost')
MONGO_PORT = int(os.environ.get('MONGO_PORT', 27017))
MONGO_DB = os.environ.get('MONGO_DB', 'cms_database')

try:
    mongo_uri = f"mongodb://{MONGO_USERNAME}:{MONGO_PASSWORD}@{MONGO_HOST}:{MONGO_PORT}/"
    client = MongoClient(
        mongo_uri,
        serverSelectionTimeoutMS=5000,
        authSource='admin',
        authMechanism='SCRAM-SHA-256'
    )
    client.admin.command('ping')
    db = client[MONGO_DB]
    users_collection = db['users']
    documents_collection = db['documents']
    
    users_collection.create_index('email', unique=True)
    users_collection.create_index('username', unique=True)
    documents_collection.create_index('author_id')
    documents_collection.create_index('created_at')
    documents_collection.create_index('status')
    documents_collection.create_index([('title', 'text'), ('content', 'text')])
    
except ConnectionFailure as e:
    print(f"Failed to connect to MongoDB: {e}")
    raise


@app.route('/health', methods=['GET'])
def health_check():
    try:
        client.admin.command('ping')
        return jsonify({'status': 'healthy', 'database': 'connected'}), 200
    except Exception as e:
        return jsonify({'status': 'unhealthy', 'error': str(e)}), 500


@app.route('/users', methods=['POST'])
def create_user():
    try:
        data = request.get_json()
        
        if not data or 'username' not in data or 'email' not in data:
            return jsonify({'error': 'Username and email are required'}), 400
        
        user = {
            'username': data['username'],
            'email': data['email'],
            'full_name': data.get('full_name', ''),
            'bio': data.get('bio', ''),
            'role': data.get('role', 'user'),
            'created_at': datetime.utcnow(),
            'updated_at': datetime.utcnow(),
            'profile_image': data.get('profile_image', ''),
            'metadata': data.get('metadata', {})
        }
        
        result = users_collection.insert_one(user)
        user['_id'] = str(result.inserted_id)
        
        return jsonify({'message': 'User created successfully', 'user_id': str(result.inserted_id)}), 201
    
    except Exception as e:
        return jsonify({'error': str(e)}), 400


@app.route('/users/<user_id>', methods=['GET'])
def get_user(user_id):
    try:
        user = users_collection.find_one({'_id': ObjectId(user_id)})
        
        if not user:
            return jsonify({'error': 'User not found'}), 404
        
        user['_id'] = str(user['_id'])
        return jsonify(user), 200
    
    except Exception as e:
        return jsonify({'error': str(e)}), 400


@app.route('/users/<user_id>', methods=['PUT'])
def update_user(user_id):
    try:
        data = request.get_json()
        
        update_fields = {}
        allowed_fields = ['full_name', 'bio', 'role', 'profile_image', 'metadata']
        
        for field in allowed_fields:
            if field in data:
                update_fields[field] = data[field]
        
        update_fields['updated_at'] = datetime.utcnow()
        
        result = users_collection.update_one(
            {'_id': ObjectId(user_id)},
            {'$set': update_fields}
        )
        
        if result.matched_count == 0:
            return jsonify({'error': 'User not found'}), 404
        
        return jsonify({'message': 'User updated successfully'}), 200
    
    except Exception as e:
        return jsonify({'error': str(e)}), 400


@app.route('/users/<user_id>', methods=['DELETE'])
def delete_user(user_id):
    try:
        result = users_collection.delete_one({'_id': ObjectId(user_id)})
        
        if result.deleted_count == 0:
            return jsonify({'error': 'User not found'}), 404
        
        return jsonify({'message': 'User deleted successfully'}), 200
    
    except Exception as e:
        return jsonify({'error': str(e)}), 400


