@app.route('/documents/search', methods=['GET'])
def search_documents():
    try:
        query = {}
        
        status = request.args.get('status')
        if status:
            query['status'] = status
        
        category = request.args.get('category')
        if category:
            query['category'] = category
        
        author_id = request.args.get('author_id')
        if author_id:
            query['author_id'] = ObjectId(author_id)
        
        tags = request.args.get('tags')
        if tags:
            query['tags'] = {'$in': tags.split(',') if ',' in tags else [tags]}
        
        search_text = request.args.get('q')
        if search_text:
            query['$text'] = {'$search': search_text}
        
        page = int(request.args.get('page', 1))
        per_page = int(request.args.get('per_page', 10))
        skip = (page - 1) * per_page
        
        sort_by = request.args.get('sort_by', 'created_at')
        sort_order = -1 if request.args.get('sort_order', 'desc') == 'desc' else 1
        
        documents = list(documents_collection.find(query)
                        .sort(sort_by, sort_order)
                        .skip(skip)
                        .limit(per_page))
        
        total = documents_collection.count_documents(query)
        
        for doc in documents:
            doc['_id'] = str(doc['_id'])
            doc['author_id'] = str(doc['author_id'])
        
        return jsonify({
            'documents': documents,
            'total': total,
            'page': page,
            'per_page': per_page,
            'total_pages': (total + per_page - 1) // per_page
        }), 200
    
    except Exception as e:
        return jsonify({'error': str(e)}), 400


@app.route('/analytics/documents-by-author', methods=['GET'])
def documents_by_author():
    try:
        pipeline = [
            {
                '$group': {
                    '_id': '$author_id',
                    'total_documents': {'$sum': 1},
                    'total_views': {'$sum': '$views'},
                    'statuses': {'$push': '$status'}
                }
            },
            {
                '$lookup': {
                    'from': 'users',
                    'localField': '_id',
                    'foreignField': '_id',
                    'as': 'author'
                }
            },
            {
                '$unwind': '$author'
            },
            {
                '$project': {
                    '_id': 0,
                    'author_id': {'$toString': '$_id'},
                    'author_name': '$author.username',
                    'total_documents': 1,
                    'total_views': 1,
                    'published_count': {
                        '$size': {
                            '$filter': {
                                'input': '$statuses',
                                'as': 'status',
                                'cond': {'$eq': ['$$status', 'published']}
                            }
                        }
                    },
                    'draft_count': {
                        '$size': {
                            '$filter': {
                                'input': '$statuses',
                                'as': 'status',
                                'cond': {'$eq': ['$$status', 'draft']}
                            }
                        }
                    }
                }
            },
            {
                '$sort': {'total_documents': -1}
            }
        ]
        
        results = list(documents_collection.aggregate(pipeline))
        
        return jsonify({'analytics': results}), 200
    
    except Exception as e:
        return jsonify({'error': str(e)}), 400


