@app.route('/analytics/activity-timeline', methods=['GET'])
def activity_timeline():
    try:
        days = int(request.args.get('days', 30))
        
        pipeline = [
            {
                '$match': {
                    'created_at': {
                        '$gte': datetime.utcnow().replace(hour=0, minute=0, second=0, microsecond=0)
                    }
                }
            },
            {
                '$group': {
                    '_id': {
                        'year': {'$year': '$created_at'},
                        'month': {'$month': '$created_at'},
                        'day': {'$dayOfMonth': '$created_at'}
                    },
                    'count': {'$sum': 1},
                    'statuses': {'$push': '$status'}
                }
            },
            {
                '$project': {
                    '_id': 0,
                    'date': {
                        '$dateFromParts': {
                            'year': '$_id.year',
                            'month': '$_id.month',
                            'day': '$_id.day'
                        }
                    },
                    'total_documents': '$count',
                    'published': {
                        '$size': {
                            '$filter': {
                                'input': '$statuses',
                                'as': 'status',
                                'cond': {'$eq': ['$$status', 'published']}
                            }
                        }
                    },
                    'draft': {
                        '$size': {
                            '$filter': {
                                'input': '$statuses',
                                'as': 'status',
                                'cond': {'$eq': ['$$status', 'draft']}
                            }
                        }
                    }
                }
            },
            {
                '$sort': {'date': -1}
            },
            {
                '$limit': days
            }
        ]
        
        results = list(documents_collection.aggregate(pipeline))
        
        for result in results:
            result['date'] = result['date'].isoformat()
        
        return jsonify({'timeline': results}), 200
    
    except Exception as e:
        return jsonify({'error': str(e)}), 400


@app.route('/users/search', methods=['GET'])
def search_users():
    try:
        query = {}
        
        role = request.args.get('role')
        if role:
            query['role'] = role
        
        username = request.args.get('username')
        if username:
            query['username'] = {'$regex': username, '$options': 'i'}
        
        page = int(request.args.get('page', 1))
        per_page = int(request.args.get('per_page', 10))
        skip = (page - 1) * per_page
        
        users = list(users_collection.find(query).skip(skip).limit(per_page))
        total = users_collection.count_documents(query)
        
        for user in users:
            user['_id'] = str(user['_id'])
        
        return jsonify({
            'users': users,
            'total': total,
            'page': page,
            'per_page': per_page,
            'total_pages': (total + per_page - 1) // per_page
        }), 200
    
    except Exception as e:
        return jsonify({'error': str(e)}), 400


